+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -866,10 +866,16 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Value *X;
   Constant *Op00C;

+  // add (umax X, C1), -C1 --> usub.sat(X, C1)
+  const APInt *C1;
+  if (match(Op0, m_OneUse(m_c_UMax(m_Value(X), m_APInt(C1)))) &&
+      match(Op1C, m_SpecificInt(-*C1)))
+    return replaceInstUsesWith(
+        Add, Builder.CreateIntrinsic(Intrinsic::usub_sat, {Ty}, {X, ConstantInt::get(Ty, *C1)}));
+
   // add (sub C1, X), C2 --> sub (add C1, C2), X
   if (match(Op0, m_Sub(m_Constant(Op00C), m_Value(X))))
     return BinaryOperator::CreateSub(ConstantExpr::getAdd(Op00C, Op1C), X);
-
   Value *Y;

   // add (sub X, Y), -1 --> add (not Y), X

